const express = require('express');
const Redis = require('ioredis');

// --- Configuration ---
const PORT = process.env.PORT || 3000;
const REDIS_HOST = process.env.REDIS_HOST || '127.0.0.1';
const REDIS_PORT = process.env.REDIS_PORT || 6379;

// --- Initialize Express App ---
const app = express();
app.use(express.json()); // Middleware to parse JSON request bodies

// --- Initialize Redis Client ---
const redis = new Redis({
  host: REDIS_HOST,
  port: REDIS_PORT,
});

// Redis error handling
redis.on('error', (err) => {
  console.error('Redis Client Error', err);
});

redis.on('connect', () => {
  console.log('Connected to Redis');
});

// --- Routes ---

// Endpoint to search for keys matching a pattern
// Example: GET /search-keys?pattern=user:*
app.get('/search-keys', async (req, res, next) => {
  const { pattern } = req.query;

  if (!pattern) {
    return res.status(400).json({ error: 'Pattern query parameter is required.' });
  }

  try {
    const keys = await redis.keys(pattern); // Uses KEYS command as requested
    res.json({ pattern, keys });
  } catch (error) {
    next(error); // Pass error to Express error handler
  }
});

// Endpoint to execute any Redis command
// Example Body:
//   { "command": "GET", "args": ["mykey"] }
//   { "command": "SET", "args": ["anotherkey", "another_value"] }
//   { "command": "HGETALL", "args": ["myhash"] }
//   { "command": "DEL", "args": ["key1", "key2"] }
app.post('/execute-command', async (req, res, next) => {
  const { command, args } = req.body; // command: string, args: array of strings

  if (!command || !Array.isArray(args)) {
    return res.status(400).json({ error: 'Both "command" (string) and "args" (array) are required in the request body.' });
  }

  try {
    // Dynamically call the Redis command using `call` method which accepts command name and arguments
    const result = await redis.call(command, ...args);
    res.json({ command, args, result });
  } catch (error) {
    next(error); // Pass error to Express error handler
  }
});

// --- Error Handling Middleware ---
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).json({
    error: 'Something went wrong!',
    details: err.message,
  });
});

// --- Start Server ---
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  console.log(`Redis connected to ${REDIS_HOST}:${REDIS_PORT}`);
});